def canPartition(self, nums: list[int]) -> bool:
    s = sum(nums)
    if s & 1:
        return False
    target = s // 2
    f = [False] * (target + 1)
    f[0] = True
    for x in nums:
        for v in range(target, x - 1, -1):
            f[v] = f[v] or f[v - x]
    return f[target]
